using TMPro;
using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// Barra de vida de boss do HUD (Tarefa #32) — scaffolding genérico, sem
/// lógica de combate própria: o script do boss (fora do âmbito desta tarefa)
/// chama <see cref="Show"/> ao iniciar o combate, <see cref="SetHealth"/> a
/// cada dano sofrido e <see cref="Hide"/> ao morrer ou ao terminar o combate.
///
/// Singleton simples (Instance), como <see cref="InteractionPromptUI"/>.
/// </summary>
public class BossHealthBarUI : MonoBehaviour
{
    public static BossHealthBarUI Instance { get; private set; }

    [SerializeField] private GameObject root;
    [SerializeField] private TMP_Text nameText;
    [Tooltip("Image do tipo 'Filled' (horizontal) — fillAmount = vida actual / vida máxima.")]
    [SerializeField] private Image fillImage;

    private float _maxHealth = 1f;

    private void Awake()
    {
        Instance = this;
        if (root != null) root.SetActive(false);
    }

    private void OnDestroy()
    {
        if (Instance == this) Instance = null;
    }

    /// <summary>Mostra a barra (cheia) para "bossName" com vida máxima "maxHealth".</summary>
    public void Show(string bossName, float maxHealth)
    {
        _maxHealth = Mathf.Max(1f, maxHealth);

        if (nameText != null) nameText.text = bossName;
        if (fillImage != null) fillImage.fillAmount = 1f;
        if (root != null) root.SetActive(true);

        // Tarefa #28 — bosses bloqueiam a regeneração automática de vida.
        PlayerHealthRegen.Instance?.SetBlocked(this, true);
    }

    /// <summary>Actualiza o preenchimento da barra para "currentHealth" (0..maxHealth definido em Show).</summary>
    public void SetHealth(float currentHealth)
    {
        if (fillImage != null) fillImage.fillAmount = Mathf.Clamp01(currentHealth / _maxHealth);
    }

    public void Hide()
    {
        if (root != null) root.SetActive(false);

        // Tarefa #28 — fim do combate de boss: desbloqueia a regeneração automática.
        PlayerHealthRegen.Instance?.SetBlocked(this, false);
    }
}
